APIClient.swift

import Foundation

enum APIError: Error, LocalizedError {
    case invalidURL
    case requestFailed(Error)
    case invalidResponse
    case httpError(statusCode: Int, data: Data?)

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "The provided URL was invalid."
        case .requestFailed(let error):
            return "Network request failed: \(error.localizedDescription)"
        case .invalidResponse:
            return "Received an invalid response from the server."
        case .httpError(let statusCode, let data):
            if let data = data, let message = String(data: data, encoding: .utf8) {
                return "Server returned HTTP \(statusCode): \(message)"
            } else {
                return "Server returned HTTP \(statusCode)."
            }
        }
    }
}

class APIClient {
    static let shared = APIClient() 
    private let session: URLSession

    private init() {
        let configuration = URLSessionConfiguration.default
        self.session = URLSession(configuration: configuration)
    }

    func performRequest(url: URL, method: String = "GET", headers: [String: String]? = nil, body: Data? = nil) async throws -> Data {
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.allHTTPHeaderFields = headers
        request.httpBody = body
        request.timeoutInterval = 30 

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard (200...299).contains(httpResponse.statusCode) else {
            throw APIError.httpError(statusCode: httpResponse.statusCode, data: data)
        }

        return data
    }

    func get(url: URL, headers: [String: String]? = nil) async throws -> Data {
        return try await performRequest(url: url, method: "GET", headers: headers)
    }

    func post(url: URL, headers: [String: String]? = nil, body: Data? = nil) async throws -> Data {
        return try await performRequest(url: url, method: "POST", headers: headers, body: body)
    }
}

