import SwiftUI

struct ContentView: View {
    @State private var cloudResponse: String = "Loading Cloud Data..."
    @State private var localResponse: String = "Loading Local Data..."
    @State private var cloudError: String?
    @State private var localError: String?

    // IMPORTANT: Replace with your actual cloud API endpoint
    private let cloudAPIURL = URL(string: "https://api.example.com/data")!
    // IMPORTANT: Replace with your actual local IoT device IP/endpoint
    // Ensure you have a device or mock server running on this IP and port for testing.
    private let localIoTURL = URL(string: "http://192.168.1.100/status")! 

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 20) {
                Text("HTTP Client Demo")
                    .font(.largeTitle)
                    .padding(.bottom)

                Group {
                    Text("Cloud API (\(cloudAPIURL.absoluteString))")
                        .font(.headline)
                    Text("Response:")
                        .font(.subheadline)
                    Text(cloudResponse)
                        .font(.body)
                        .foregroundColor(.green)
                    if let error = cloudError {
                        Text("Error: \(error)")
                            .font(.body)
                            .foregroundColor(.red)
                    }
                    Button("Fetch Cloud Data") {
                        fetchCloudData()
                    }
                }
                .padding(.bottom)

                Divider()

                Group {
                    Text("Local IoT Device (\(localIoTURL.absoluteString))")
                        .font(.headline)
                    Text("Response:")
                        .font(.subheadline)
                    Text(localResponse)
                        .font(.body)
                        .foregroundColor(.green)
                    if let error = localError {
                        Text("Error: \(error)")
                            .font(.body)
                            .foregroundColor(.red)
                    }
                    Button("Fetch Local Data") {
                        fetchLocalData()
                    }
                }
            }
            .padding()
            .onAppear {
                fetchCloudData()
                fetchLocalData()
            }
        }
    }

    private func fetchCloudData() {
        Task {
            cloudResponse = "Fetching..."
            cloudError = nil
            do {
                let data = try await APIClient.shared.get(url: cloudAPIURL)
                if let jsonString = String(data: data, encoding: .utf8) {
                    cloudResponse = "Success: \(jsonString)"
                } else {
                    cloudResponse = "Success: Data could not be decoded as String."
                }
            } catch {
                if let apiError = error as? APIError {
                    cloudError = apiError.localizedDescription
                } else {
                    cloudError = "An unexpected error occurred: \(error.localizedDescription)"
                }
                cloudResponse = "Failed."
            }
        }
    }

    private func fetchLocalData() {
        Task {
            localResponse = "Fetching..."
            localError = nil
            do {
                let data = try await APIClient.shared.get(url: localIoTURL)
                if let jsonString = String(data: data, encoding: .utf8) {
                    localResponse = "Success: \(jsonString)"
                } else {
                    localResponse = "Success: Data could not be decoded as String."
                }
            } catch {
                if let apiError = error as? APIError {
                    localError = apiError.localizedDescription
                } else {
                    localError = "An unexpected error occurred: \(error.localizedDescription)"
                }
                localResponse = "Failed."
            }
        }
    }
}